//! grove — Phase 1: one engine, two faces.
//!
//! The same operations are exposed as a human CLI (`grove outline …`) and as an
//! MCP server (`grove serve`). Both call `ops`; neither owns engine logic.

mod engine;
mod fetch;
mod ingest;
mod init;
mod mcp;
mod ops;
mod registry;

use std::path::PathBuf;

use anyhow::Result;
use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(name = "grove", version, about = "Structural sight for coding agents (Phase 1)")]
struct Cli {
    /// Emit JSON instead of the human table.
    #[arg(long, global = true)]
    json: bool,
    #[command(subcommand)]
    cmd: Cmd,
}

#[derive(Subcommand)]
enum Cmd {
    /// List the definitions in one file (kind · name · parent · signature · id).
    Outline {
        file: PathBuf,
        /// Only this kind (e.g. class, function, method).
        #[arg(long)]
        kind: Option<String>,
        /// JSON detail: 0 terse · 1 default (no byte offsets) · 2 full.
        #[arg(long, default_value_t = 1)]
        detail: u8,
    },
    /// Find symbols across a directory, optionally filtered.
    Symbols {
        dir: PathBuf,
        /// Only this kind (e.g. function, struct, method).
        #[arg(long)]
        kind: Option<String>,
        /// Only definitions whose name equals this exactly (case-insensitive).
        #[arg(long)]
        name: Option<String>,
        /// Substring matching for --name (case-insensitive) instead of exact equality.
        #[arg(long = "name-contains", alias = "name-substr")]
        name_contains: bool,
        /// Include references, not just definitions.
        #[arg(long)]
        refs: bool,
    },
    /// Print the full source of a symbol, by id or by file + name.
    Source {
        /// A symbol id from outline/symbols, e.g. rust:src/lib.rs#parse@41
        id_or_file: String,
        /// If the first arg is a file, the symbol name to find in it.
        name: Option<String>,
    },
    /// Report ERROR / MISSING nodes — a post-edit syntax check.
    Check { file: PathBuf },
    /// Find references to a symbol across a directory (structural + textual).
    Callers {
        /// The symbol name to find references to.
        name: String,
        /// Directory to search.
        #[arg(short, long, default_value = ".")]
        dir: PathBuf,
    },
    /// Compact structural map: definitions and their references, no source bodies.
    Map {
        dir: PathBuf,
        /// Only definitions of this kind (e.g. function, class, method).
        #[arg(long)]
        kind: Option<String>,
        /// Only definitions whose name equals this exactly (case-insensitive).

        /// Only definitions whose name equals this exactly (case-insensitive).
        #[arg(long)]
        name: Option<String>,
        /// Substring matching for --name (case-insensitive) instead of exact equality.
        #[arg(long = "name-contains", alias = "name-substr")]
        name_contains: bool,
    },
    /// Find where a symbol is defined (go-to-def), by name or by position.
    ///
    /// `name` is an exact-name lookup (may return several candidates). `--at` is
    /// the precise mode: it resolves the identifier under a usage site,
    /// scope-aware (a local/parameter shadows a same-named global) and following
    /// imports across files, falling back to name lookup when it can't resolve.
    Definition {
        /// The symbol name to resolve (omit when using --at).
        name: Option<String>,
        /// Directory to search.
        #[arg(short, long, default_value = ".")]
        dir: PathBuf,
        /// Resolve the identifier at a usage site: file:line:col (1-based).
        /// Scope-aware + cross-file; prefer this when you have a position.
        #[arg(long)]
        at: Option<String>,
    },
    /// Set up grove in a project: fetch grammars + grove.lock, and wire up the
    /// chosen integration (MCP server, the cross-harness skill, or both).
    Init {
        /// Project directory (default: current).
        #[arg(default_value = ".")]
        path: PathBuf,
        /// Which integration to set up: mcp (default), skill, or both.
        #[arg(long = "as", value_enum, default_value_t = init::Target::Mcp)]
        target: init::Target,
        /// Show what would be detected/written without writing.
        #[arg(long)]
        dry_run: bool,
    },
    /// Download grammars from the hosted registry into the OS cache.
    Fetch {
        /// Languages to fetch (default: all in the catalog).
        langs: Vec<String>,
        /// Re-download even if already cached.
        #[arg(long)]
        force: bool,
    },
    /// Build registry artifacts from curated source specs (registry maintainer step).
    Ingest {
        /// Only these languages (default: all in the sources file).
        only: Vec<String>,
        /// Curated sources spec.
        #[arg(long, default_value = "registry-sources.json")]
        sources: PathBuf,
        /// Output registry directory.
        #[arg(long, default_value = "registry")]
        out: PathBuf,
    },
    /// Build the hosted catalog (index.json) for a registry directory.
    Index {
        /// Registry directory to index (default: the resolved registry root).
        dir: Option<PathBuf>,
        /// Output path (default: <dir>/index.json).
        #[arg(short, long)]
        output: Option<PathBuf>,
        /// Serve grammar.wasm as release assets from this base URL (GitHub Releases).
        #[arg(long)]
        release_base: Option<String>,
    },
    /// Show the resolved registry location and search order.
    Registry,
    /// List the languages available in the registry.
    Languages,
    /// Write grove.lock pinning each registry grammar's version + content hash.
    Lock,
    /// Run as an MCP server over stdio (the agent-facing face).
    Serve,
}

fn main() -> Result<()> {
    let cli = Cli::parse();
    match cli.cmd {
        Cmd::Outline { file, kind, detail } => {

        Cmd::Outline { file, kind, detail } => {
            let syms = ops::outline(&file, kind.as_deref())?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&ops::project(&syms, detail))?);
            } else {
                for s in &syms {
                    let owner = s.parent.clone().unwrap_or_default();
                    println!("{:<10} {:<26} {:<18} {}:{:<4} {}", s.kind, s.name, owner, s.line, s.col, s.signature);
                }
                eprintln!("\n{} definitions · {}", syms.len(), ops::rel(&file));
            }
        }
        Cmd::Symbols { dir, kind, name, name_contains, refs } => {
            let syms = ops::symbols(&dir, kind.as_deref(), name.as_deref(), refs, name_contains)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&syms)?);
            } else {
                for s in &syms {
                    let mark = if s.is_definition { "def" } else { "ref" };
                    println!("{:<3} {:<10} {:<28} {}", mark, s.kind, s.name, s.id);
                }
                eprintln!("\n{} symbols", syms.len());
            }
        }
        Cmd::Source { id_or_file, name } => {
            let res = ops::source(&id_or_file, name.as_deref())?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&res)?);
            } else {
                if !res.other_candidates.is_empty() {
                    eprintln!("(also matched: {})", res.other_candidates.join(", "));
                }
                println!("{}", res.source);
            }
        }
        Cmd::Check { file } => {
            let defects = ops::check(&file)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&defects)?);
            } else if defects.is_empty() {
                println!("ok · no syntax errors · {}", ops::rel(&file));
            } else {
                for d in &defects {
                    println!("{:<8} {}:{:<4} `{}`", d.kind, d.line, d.col, d.text);
                }
                eprintln!("\n{} defect(s) · {}", defects.len(), ops::rel(&file));
                std::process::exit(1);
            }
        }
        Cmd::Callers { name, dir } => {
            let sites = ops::callers(&dir, &name)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&sites)?);
            } else {
                for s in &sites {
                    let inf = s.in_function.as_deref().unwrap_or("<top-level>");
                    // Lead with `path:line:col` so the location is greppable and,
                    // for a directory-wide query, you can tell which file it's in (#29).
                    // [S]/[T] = structural (tree-sitter) vs textual (grep) provenance (#33).
                    let tag = if s.source == "structural" { "S" } else { "T" };
                    println!("{}:{}:{}   {:<28} [{}] {}", s.file, s.line, s.col, inf, tag, s.text);
                }
                eprintln!("\n{} reference(s) of `{}` (S=structural, T=textual)", sites.len(), name);
            }
        }
        Cmd::Map { dir, kind, name, name_contains } => {
            let maps = ops::map(&dir, kind.as_deref(), name.as_deref(), name_contains)?;
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&maps)?);
            } else {
                for fm in &maps {
                    println!("{}", fm.file);
                    for e in &fm.entries {
                        let parent = e.parent.as_deref().unwrap_or("");
                        if e.references.is_empty() {
                            println!("  {:<10} {:<26} {:<18} {:<4} {}", e.kind, e.name, parent, e.row, e.signature);
                        } else {
                            println!("  {:<10} {:<26} {:<18} {:<4} {}  → {}", e.kind, e.name, parent, e.row, e.signature, e.references.join(", "));
                        }
                    }
                }
                let total: usize = maps.iter().map(|fm| fm.entries.len()).sum();
                eprintln!("\n{} definitions across {} files", total, maps.len());
            }
        }
        Cmd::Definition { name, dir, at } => {
            let (resolved, defs) = match at {
                Some(pos) => {
                    let (file, row, col) = ops::parse_pos(&pos)?;
                    ops::definition_at(&file, row, col, &dir)?
                }
                None => {
                    let name = name.ok_or_else(|| anyhow::anyhow!("provide a name or --at"))?;
                    (name.clone(), ops::definition(&dir, &name)?)
                }
            };
            if cli.json {
                println!("{}", serde_json::to_string_pretty(&defs)?);
            } else {
                for s in &defs {
                    let owner = s.parent.clone().unwrap_or_default();
                    // `definition` searches a whole dir, so results can span
                    // files — lead with `file:line:col` so the caller knows
                    // which file each hit is in without a follow-up `symbols`.
                    let loc = format!("{}:{}:{}", s.file, s.line, s.col);
                    println!("{:<10} {:<26} {:<18} {:<28} {}", s.kind, s.name, owner, loc, s.signature);
                }
                eprintln!("\n{} definition(s) of `{}`", defs.len(), resolved);
            }
        }
        Cmd::Init { path, target, dry_run } => init::run(&path, target, dry_run)?,
        Cmd::Fetch { langs, force } => fetch::run(&langs, force)?,
        Cmd::Ingest { only, sources, out } => ingest::run(&sources, &out, &only)?,
        Cmd::Index { dir, output, release_base } => {
            let (out, n) = registry::write_index(dir, output, release_base.as_deref())?;
            println!("wrote {} ({n} grammars)", out.display());
        }
        Cmd::Registry => {
            println!("registry root: {}\n", registry::root().display());
            println!("search order (first existing wins):");
            for c in registry::search_path() {
                let mark = if c.exists { "✓" } else { "·" };
                println!("  {mark} {:<26} {}", c.source, c.path.display());
            }
        }
        Cmd::Languages => {
            let manifests = registry::manifests();
            if cli.json {
                let v: Vec<_> = manifests
                    .iter()
                    .map(|m| serde_json::json!({"name": m.name, "version": m.version, "extensions": m.extensions}))
                    .collect();
                println!("{}", serde_json::to_string_pretty(&v)?);
            } else {
                for m in &manifests {
                    println!("{:<12} {:<10} .{}", m.name, m.version, m.extensions.join(" ."));
                }
                eprintln!("\n{} language(s) in registry", manifests.len());
            }
        }
        Cmd::Lock => {
            let lock = registry::write_lock(std::path::Path::new("grove.lock"))?;
            println!("wrote grove.lock ({} grammars)", lock);
        }
        Cmd::Serve => mcp::serve()?,
    }
    Ok(())
}

//! The structural engine: parse + tag extraction + syntax check, over grammars
//! loaded from the registry as wasm.
//!
//! Tags are extracted by running the grammar's `tags.scm` through the Query
//! engine (interpreting `@definition.*` / `@reference.*` / `@name` captures),
//! because `tree-sitter-tags` cannot drive a wasm-loaded language. The same path
//! serves every language, static or wasm.

use std::cell::RefCell;
use std::collections::HashMap;
use std::sync::OnceLock;

use anyhow::{anyhow, Context, Result};
use serde::Serialize;
use streaming_iterator::StreamingIterator;
use tree_sitter::{Language, Node, Parser, Query, QueryCursor, WasmStore};

use crate::registry::{Grammar, Profile};

/// A definition or reference extracted from a file.
#[derive(Debug, Serialize)]
pub struct Symbol {
    /// Stable handle: `<lang>:<relpath>#<name>@<line>` (line is 1-based). Survives across turns.
    pub id: String,
    pub name: String,
    /// e.g. `function`, `method`, `class`, `call` — from the grammar's tag query.
    pub kind: String,
    pub is_definition: bool,
    pub file: String,
    /// 1-based line and column of the name — the editor / `grep -n` convention,
    /// so a citation printed as "line N" lands on the right line. (tree-sitter's
    /// own `Point` is 0-based; we normalize here. The byte range below, not these,
    /// is what `source` slices.)
    pub line: usize,
    pub col: usize,
    /// Byte range of the whole symbol (what `source` slices).
    pub start_byte: usize,
    pub end_byte: usize,
    /// The trimmed source line containing the name — a compact signature.
    pub signature: String,
    /// The owning container — the `impl` type, trait, class, or module.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub parent: Option<String>,
}

/// A syntactic defect found by `check`.
#[derive(Debug, Serialize)]
pub struct Defect {
    pub kind: &'static str,
    /// 1-based line and column — same editor / `grep -n` convention as `Symbol`.
    pub line: usize,
    pub col: usize,
    pub start_byte: usize,
    pub end_byte: usize,
    pub text: String,
}

// The per-language node-kind profile is data now — it comes from the grammar's
// manifest (`registry::Profile`), not a table compiled in here.

// ---- loaded-grammar cache (load each wasm grammar once per process) ----

fn engine() -> &'static tree_sitter::wasmtime::Engine {
    static E: OnceLock<tree_sitter::wasmtime::Engine> = OnceLock::new();
    E.get_or_init(tree_sitter::wasmtime::Engine::default)
}

struct Loaded {
    parser: Parser,
    /// Held to anchor the wasm-loaded language's lifetime alongside its store.
    #[allow(dead_code)]
    language: Language,
    tags_query: Query,
    capture_names: Vec<String>,
    /// Compiled `locals.scm`, with its capture-name table. `None` when the
    /// grammar ships no locals query.
    locals: Option<CapturedQuery>,
    /// Compiled `imports.scm`, with its capture-name table. `None` when the
    /// grammar ships no imports query.
    imports: Option<CapturedQuery>,
}

/// A compiled query plus its capture-name lookup table.
struct CapturedQuery {
    query: Query,
    capture_names: Vec<String>,
}

impl CapturedQuery {
    fn compile(language: &Language, src: &str, what: &str) -> Result<CapturedQuery> {
        let query = Query::new(language, src).with_context(|| format!("compiling {what} query"))?;
        let capture_names = query.capture_names().iter().map(|s| s.to_string()).collect();
        Ok(CapturedQuery { query, capture_names })
    }

    /// Compile an *optional* query (`locals.scm` / `imports.scm`) without letting
    /// a bad one break the grammar. These come from the registry and may be
    /// authored upstream against a different grammar version; a query that fails
    /// to compile (e.g. references a node kind this grammar doesn't have) must
    /// degrade to "feature off", never poison the core tools. Returns `None` on

//! MCP server — the second face. Speaks newline-delimited JSON-RPC 2.0 over
//! stdio (the MCP stdio transport), exposing the four ops as tools.
//!
//! Deliberately dependency-light: the protocol surface for a tools-only server
//! is small, so we hand-roll it rather than pull an async SDK. stdout is the
//! protocol channel — all diagnostics go to stderr.

use std::io::{BufRead, Write};
use std::path::PathBuf;

use anyhow::Result;
use serde_json::{json, Value};

use crate::{ops, registry};

const SERVER_NAME: &str = "grove";
const SERVER_VERSION: &str = env!("CARGO_PKG_VERSION");
const DEFAULT_PROTOCOL: &str = "2025-06-18";

/// MCP revisions grove's minimal tools surface is compatible with. On
/// `initialize` we echo the client's version when it's one of these, otherwise
/// we answer with our latest (`DEFAULT_PROTOCOL`) rather than parroting an
/// unknown version back (which would falsely claim support).
const SUPPORTED_PROTOCOLS: &[&str] = &["2025-06-18", "2025-03-26", "2024-11-05"];

/// Run the stdio server loop until EOF on stdin.
pub fn serve() -> Result<()> {
    let stdin = std::io::stdin();
    let mut stdout = std::io::stdout();
    eprintln!("grove mcp: ready on stdio");

    for line in stdin.lock().lines() {
        let line = line?;
        if line.trim().is_empty() {
            continue;
        }
        let req: Value = match serde_json::from_str(&line) {
            Ok(v) => v,
            Err(e) => {
                eprintln!("grove mcp: bad json: {e}");
                continue;
            }
        };

        // Notifications (no `id`) get no response.
        let id = req.get("id").cloned();
        let method = req.get("method").and_then(Value::as_str).unwrap_or("");
        let params = req.get("params").cloned().unwrap_or(Value::Null);

        let response = match handle(method, &params) {
            Outcome::Notify => continue,
            Outcome::Ok(result) => json!({ "jsonrpc": "2.0", "id": id, "result": result }),
            Outcome::Err { code, message } => json!({
                "jsonrpc": "2.0",
                "id": id,
                "error": { "code": code, "message": message },
            }),
        };
        if id.is_none() {
            continue; // method was a request-shaped notification; still no reply
        }
        writeln!(stdout, "{response}")?;
        stdout.flush()?;
    }
    Ok(())
}

enum Outcome {
    Ok(Value),
    Err { code: i64, message: String },
    Notify,
}

fn handle(method: &str, params: &Value) -> Outcome {
    match method {
        "initialize" => {
            // Answer with the client's version only if we support it; otherwise
            // our latest. Never echo an unknown version (would imply support).
            let requested = params.get("protocolVersion").and_then(Value::as_str);
            let protocol = match requested {

            let protocol = match requested {
                Some(v) if SUPPORTED_PROTOCOLS.contains(&v) => v,
                _ => DEFAULT_PROTOCOL,
            };
            Outcome::Ok(json!({
                "protocolVersion": protocol,
                "capabilities": { "tools": { "listChanged": false } },
                "serverInfo": { "name": SERVER_NAME, "title": "grove", "version": SERVER_VERSION },
                "instructions": instructions(),
            }))
        }
        "notifications/initialized" | "notifications/cancelled" => Outcome::Notify,
        "ping" => Outcome::Ok(json!({})),
        "tools/list" => Outcome::Ok(json!({ "tools": tool_specs() })),
        "tools/call" => call_tool(params),
        other => Outcome::Err {
            code: -32601,
            message: format!("method not found: {other}"),
        },
    }
}

/// Server-level steering, returned from `initialize`. This is the protocol-layer
/// home for grove's adoption nudge (VISION §6.4.1) and the one place the resolved
/// language roster lives, so tool descriptions stay generic and token-cheap.
fn instructions() -> String {
    let langs = registry::available();
    let roster = if langs.is_empty() {
        "No grammars are installed yet — run `grove fetch <lang>` (or `grove init`).".to_string()
    } else {
        format!("Languages available here: {}.", langs.join(", "))
    };
    format!(
        "grove gives byte-precise, token-cheap structural access to this codebase. \
Prefer these tools over grep or reading whole files: `map` for a directory-level \
dependency graph (definitions + which other symbols each one references — replaces \
many symbols+source round-trips with one call), `outline` to see a file's \
definitions, `symbols`/`definition` to locate code, `source` to read one \
symbol's body, `callers` to find call sites, and `check` after an edit to \
verify syntax. Every result carries a stable symbol-id \
(`<lang>:<relpath>#<name>@<line>`, line 1-based) you can pass between tools. {roster}\n\n\
Breadth control: prefer `map` for architectural overviews — it returns the \
definition-and-reference graph of a directory in one call. Use `source` only \
for the few load-bearing definitions you need to read in full. Avoid fetching \
many sources in sequence; instead map first, then read only the symbols that matter."
    )
}

/// The tool catalogue, with LLM-facing descriptions. Descriptions are
/// language-agnostic — grove serves every installed grammar, and the resolved
/// language list is provided once via `initialize`'s `instructions`.
///
/// Every `inputSchema` is a plain `{type: object, properties, required?}`. Do
/// **not** use a top-level `anyOf`/`oneOf` to express "one arg form or the
/// other": some MCP clients can't normalize that and silently drop the tool
/// from the registered set (it was why `source`/`definition` once went missing
/// while the four flat-schema tools registered fine). For mutually-exclusive
/// argument forms, leave the alternatives optional here and enforce the choice
/// in `call_tool`, which returns a clear `isError` when neither is supplied.
fn tool_specs() -> Value {
    json!([
        {
            "name": "outline",
            "description": "List the definitions in one source file as a compact skeleton (kind, name, signature line, position, a stable symbol-id, and the owning `parent` container — the type/class/trait/module a member belongs to, so you can group members without guessing from line numbers). Works on any source file in a language grove has a grammar for. Use this INSTEAD of reading a whole file. For large, definition-dense files, pass `kind` to narrow and/or a lower `detail` to stay token-cheap. Returns JSON.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "file": { "type": "string", "description": "Path to a source file" },
                    "kind": { "type": "string", "description": "Only this kind (kinds are language-dependent), e.g. class, struct, function, method, module" },
                    "detail": { "type": "integer", "enum": [0, 1, 2], "description": "0 terse (kind/name/parent/line) · 1 default (adds id/signature) · 2 full (adds byte offsets). Default 1." }
                },
                "required": ["file"]
            },
            "annotations": { "title": "Outline a file", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "symbols",
            "description": "Find symbols across a directory (gitignore-aware), in any language grove has a grammar for. Filter by kind (function, method, class, struct, …) and/or a name. `name` matches exactly (case-insensitive); set `nameContains` true for substring matching. Use this to locate where something is defined instead of grepping. Returns JSON with stable symbol-ids. For a structured overview with reference edges, prefer `map` — it returns definitions and their outgoing references in one call, replacing many `symbols`+`source` round-trips.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "dir": { "type": "string", "description": "Directory to search" },
                    "kind": { "type": "string", "description": "Only this kind, e.g. function, class, method (language-dependent)" },
                    "name": { "type": "string", "description": "Only definitions whose name equals this exactly (case-insensitive)" },
                    "nameContains": { "type": "boolean", "description": "Substring matching for `name` instead of exact equality (case-insensitive). Default false." },
                    "refs": { "type": "boolean", "description": "Include references, not just definitions (default false)" }
                },
                "required": ["dir"]
            },
            "annotations": { "title": "Find symbols", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "source",
            "description": "Return the exact full source of one symbol — by its symbol-id (from outline/symbols/map), or by file + name. Use sparingly — read one symbol at a time, only when you need its full implementation. For architectural understanding, prefer `map` (directory-level dependency graph in one call) or `outline` (file skeleton without bodies). If several definitions share the name, returns the first plus `other_candidates` (their ids) so you can disambiguate without another call. Returns JSON { id, source, other_candidates? }.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "id": { "type": "string", "description": "A symbol-id like <lang>:<relpath>#<name>@<line> (e.g. py:app/main.py#run@41); line is 1-based" },
                    "file": { "type": "string", "description": "Alternatively, the source file (with `name`)" },
                    "name": { "type": "string", "description": "…and the symbol name to find in it" }
                }
            },
            "annotations": { "title": "Read a symbol's source", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "check",
            "description": "Parse a source file and report syntax errors (ERROR / MISSING nodes) with positions, in any language grove has a grammar for. Use this AFTER editing a file to confirm you did not break its syntax. Reports syntactic breakage only, not type or semantic errors. Returns JSON; empty array means the file is syntactically valid.",
            "inputSchema": {
                "type": "object",
                "properties": { "file": { "type": "string", "description": "Path to a source file" } },
                "required": ["file"]
            },
            "annotations": { "title": "Check syntax", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "callers",
            "description": "Find every reference to a symbol by name across a directory, with enclosing function and source line. Returns two kinds of results: 'structural' (tree-sitter resolved, high precision) and 'textual' (whole-word grep, high recall — covers type annotations, imports, and references the tags query misses). Use this to answer 'what calls this?' or 'where is this used?'. Name-based — matches any symbol with this name, not resolved by receiver type. For a broad call-graph view of a directory, prefer `map`. Returns JSON.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "name": { "type": "string", "description": "Function/method name to find calls to" },

                    "name": { "type": "string", "description": "Function/method name to find calls to" },
                    "dir": { "type": "string", "description": "Directory to search (default: current)" }
                },
                "required": ["name"]
            },
            "annotations": { "title": "Find callers", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "map",
            "description": "Return a compact structural map of a directory: every definition grouped by file, with each definition's outgoing references (which other symbols it calls or uses). No source bodies — just the dependency graph. Use this instead of many symbols+source calls when you need a broad picture of how code connects. Prefer map for architectural understanding; use source only for the few load-bearing definitions you need to read in full. Filter by kind or name (`name` is exact, case-insensitive; set `nameContains` true for substring) to narrow the view. Returns JSON.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "dir": { "type": "string", "description": "Directory to map" },
                    "kind": { "type": "string", "description": "Only definitions of this kind, e.g. function, class, method" },
                    "name": { "type": "string", "description": "Only definitions whose name equals this exactly (case-insensitive)" },
                    "nameContains": { "type": "boolean", "description": "Substring matching for `name` instead of exact equality (case-insensitive). Default false." }
                },
                "required": ["dir"]
            },
            "annotations": { "title": "Map a directory's structure", "readOnlyHint": true, "openWorldHint": false }
        },
        {
            "name": "definition",
            "description": "Find where a symbol is defined (go-to-def). Two modes. `name`: exact-name lookup across the directory — may return several candidates when a name is reused. `at` (file:line:col, 1-based): resolve the identifier under a *usage site* — the precise mode, preferred whenever you have a position. It is scope-aware (a local/parameter binding wins over a same-named global) and follows import edges across files (an imported symbol resolves to its definition in the target file), so it returns the single binding the cursor actually refers to instead of a candidate list. Falls back to name lookup when it can't resolve (e.g. a re-exported or dynamically imported symbol), so it is never worse than `name`. Returns JSON definitions with signature, parent, and id.",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "name": { "type": "string", "description": "Exact symbol name to resolve (provide this or `at`)" },
                    "at": { "type": "string", "description": "Usage site to resolve, scope-aware + cross-file: file:line:col (1-based). Prefer this when you have a position." },
                    "dir": { "type": "string", "description": "Directory to search (default: current)" }
                }
            },
            "annotations": { "title": "Go to definition", "readOnlyHint": true, "openWorldHint": false }
        }
    ])
}

fn call_tool(params: &Value) -> Outcome {
    let name = params.get("name").and_then(Value::as_str).unwrap_or("");
    let args = params.get("arguments").cloned().unwrap_or(Value::Null);
    let str_arg = |k: &str| args.get(k).and_then(Value::as_str).map(str::to_string);

    let result: Result<Value> = match name {
        "outline" => match str_arg("file") {
            Some(f) => match outline_detail(&args) {
                Ok(detail) => ops::outline(&PathBuf::from(f), str_arg("kind").as_deref())
                    .map(|syms| ops::project(&syms, detail)),
                Err(e) => Err(e),
            },
            None => missing("file"),
        },
        "symbols" => match str_arg("dir") {
            Some(d) => ops::symbols(
                &PathBuf::from(d),
                str_arg("kind").as_deref(),
                str_arg("name").as_deref(),
                args.get("refs").and_then(Value::as_bool).unwrap_or(false),
                args.get("nameContains").and_then(Value::as_bool).unwrap_or(false),
            )
            .and_then(to_json),
            None => missing("dir"),
        },
        "source" => {
            if let Some(id) = str_arg("id") {
                ops::source(&id, None).and_then(to_json)
            } else if let (Some(file), Some(n)) = (str_arg("file"), str_arg("name")) {
                ops::source(&file, Some(&n)).and_then(to_json)
            } else {
                Err(anyhow::anyhow!("provide either `id`, or both `file` and `name`"))
            }
        }
        "check" => match str_arg("file") {
            Some(f) => ops::check(&PathBuf::from(f)).and_then(to_json),
            None => missing("file"),
        },
        "callers" => match str_arg("name") {
            Some(n) => {
                let dir = str_arg("dir").unwrap_or_else(|| ".".to_string());
                ops::callers(&PathBuf::from(dir), &n).and_then(to_json)
            }
            None => missing("name"),
        },
        "map" => match str_arg("dir") {
            Some(d) => ops::map(
                &PathBuf::from(d),
                str_arg("kind").as_deref(),
                str_arg("name").as_deref(),
                args.get("nameContains").and_then(Value::as_bool).unwrap_or(false),
            )
            .and_then(to_json),
            None => missing("dir"),
        },
        "definition" => {
            // One shape for both modes — `{resolved, definitions}` — so a client
            // never has to branch on which argument it passed. In `at` mode
            // `resolved` is the name grove resolved at the position; in `name`
            // mode it is simply the name the caller supplied.
            let dir = PathBuf::from(str_arg("dir").unwrap_or_else(|| ".".to_string()));
            if let Some(at) = str_arg("at") {
                match ops::parse_pos(&at) {
                    Ok((file, row, col)) => ops::definition_at(&file, row, col, &dir)
                        .map(|(name, defs)| json!({ "resolved": name, "definitions": defs })),
                    Err(e) => Err(e),
                }
            } else if let Some(name) = str_arg("name") {
                ops::definition(&dir, &name)
                    .map(|defs| json!({ "resolved": name, "definitions": defs }))
            } else {
                Err(anyhow::anyhow!("provide either `name` or `at`"))
            }
        }
        other => {
            return Outcome::Err {
                code: -32602,
                message: format!("unknown tool: {other}"),
            }
        }
    };

    match result {
        Ok(value) => Outcome::Ok(tool_text(&value, false)),
        // Tool-level failures are reported as a result with isError, per MCP,
        // so the model sees the message and can recover rather than the whole
        // call erroring out.
        Err(e) => Outcome::Ok(tool_text(&json!(e.to_string()), true)),
    }
}

fn to_json<T: serde::Serialize>(v: T) -> Result<Value> {
    Ok(serde_json::to_value(v)?)
}

fn missing(field: &str) -> Result<Value> {
    Err(anyhow::anyhow!("missing required argument: {field}"))
}

/// Resolve the `outline` `detail` tier, validating it against the advertised
/// `enum [0,1,2]`. Absent means the default (1). Anything else is an error —
/// never a silent `as u8` truncation (`256` -> `0`) that serves the wrong tier.
fn outline_detail(args: &Value) -> Result<u8> {
    match args.get("detail") {
        None | Some(Value::Null) => Ok(1),
        Some(v) => match v.as_u64() {
            Some(d @ (0 | 1 | 2)) => Ok(d as u8),
            _ => Err(anyhow::anyhow!("`detail` must be 0, 1, or 2 (got {v})")),
        },
    }
}

/// Wrap a JSON value as an MCP tool result (a single text content block).

//! The operations, as a library — the single engine both faces call.
//!
//! `main.rs` (CLI) formats these into human tables; `mcp.rs` (MCP server)
//! serializes them to JSON. Grammars come from the registry, so these work for
//! any registered language, not just one compiled in.

use std::path::{Path, PathBuf};

use anyhow::{Context, Result};
use serde::Serialize;

use crate::engine::{self, Defect, Symbol};
use crate::registry::{self, Grammar};
use ignore::WalkBuilder;

/// Read a file's bytes with a contextual error.
pub fn read(path: &Path) -> Result<Vec<u8>> {
    std::fs::read(path).with_context(|| format!("reading {}", path.display()))
}

/// Best-effort repo-relative path, for stable symbol ids.
pub fn rel(path: &Path) -> String {
    std::env::current_dir()
        .ok()
        .and_then(|cwd| path.canonicalize().ok().map(|p| (cwd, p)))
        .and_then(|(cwd, p)| p.strip_prefix(&cwd).ok().map(|r| r.display().to_string()))
        .unwrap_or_else(|| path.display().to_string())
}

/// True if `path` is a generated declaration file grove should not index as
/// source during a directory walk. TypeScript `.d.ts`/`.d.cts`/`.d.mts` files
/// are type declarations with no implementation — often machine-generated
/// (under `tests/baselines/`, `declarations/`, `dist/`). Indexing them points
/// `symbols`/`definition`/`callers` at the decl instead of the real source and
/// drops genuine call sites, so they are excluded from the walk. A single
/// file requested explicitly via `outline`/`source`/`check` is still honored —
/// this filter only governs the recursive indexing pass. (Issue #32.)
fn is_generated_decl(path: &Path) -> bool {
    let Some(name) = path.file_name().and_then(|n| n.to_str()) else {
        return false;
    };
    name.ends_with(".d.ts") || name.ends_with(".d.cts") || name.ends_with(".d.mts")
}

/// Walk every registered-source file under `dir`, yielding `(grammar, relpath, source)`.
/// Generated declaration files (`*.d.ts`, see [`is_generated_decl`]) are skipped
/// so `symbols`/`definition`/`callers` answer from real source, not generated decls.
fn for_each_source(dir: &Path, mut f: impl FnMut(&Grammar, &str, &[u8]) -> Result<()>) -> Result<()> {
    for entry in WalkBuilder::new(dir).build() {
        let entry = match entry {
            Ok(e) => e,
            Err(_) => continue,
        };
        let path = entry.path();
        if !path.is_file() || !registry::is_source(path) || is_generated_decl(path) {
            continue;
        }
        let grammar = registry::for_path(path)?;
        let src = read(path)?;
        f(&grammar, &rel(path), &src)?;
    }
    Ok(())
}

/// Whether a symbol of `sym_kind` satisfies a `--kind filter`. Exact match,
/// plus synonyms so a natural term finds the umbrella kind grove actually emits:
/// every grammar tags struct/class-likes as `class` (C/Rust structs, C unions),
/// so `--kind struct`/`--kind union` still find them. The aliases map onto
/// `class` only — no grammar emits `struct`/`union` as a kind — so this can only
/// widen a match, never hide one.
fn kind_matches(sym_kind: &str, filter: &str) -> bool {
    sym_kind == filter
        || (matches!(filter, "struct" | "union" | "record") && sym_kind == "class")
}

/// Compare a symbol's name against a lowercased query. By default **exact**
/// (case-insensitive) equality — so `--name batch` returns `batch`, not
/// `testCreateBatch` (issue #37). With `contains` true, falls back to substring
/// matching (the `--name-contains` opt-in) for fuzzy exploration. Grammar-common:
/// it operates on the already-extracted `Symbol.name` string, so one rule serves
/// every language.
fn name_matches(sym_name: &str, query_lc: &str, contains: bool) -> bool {
    let sym_lc = sym_name.to_lowercase();
    if contains {
        sym_lc.contains(query_lc)
    } else {
        sym_lc == query_lc
    }
}

/// `outline` — the definitions in one file, optionally filtered by kind.
pub fn outline(file: &Path, kind: Option<&str>) -> Result<Vec<Symbol>> {
    let grammar = registry::for_path(file)?;
    let src = read(file)?;
    let mut syms = engine::extract(&grammar, &rel(file), &src)?;
    syms.retain(|s| s.is_definition && kind.is_none_or(|k| kind_matches(&s.kind, k)));
    Ok(syms)
}

/// Project symbols to a JSON array at a detail level, to keep payloads bounded:

//! The grammar registry — Phase 2 spine.
//!
//! Resolves a language id (or a file path) to its wasm grammar + tags query,
//! loaded at runtime. The local-directory stub here (`registry/<lang>/` with
//! `grammar.wasm`, `tags.scm`, `manifest.json`) stands in for the future hosted
//! WASM registry; nothing above this module knows grammars aren't compiled in.

use std::collections::HashMap;
use std::path::{Path, PathBuf};
use std::sync::{Arc, Mutex, OnceLock};

use anyhow::{Context, Result};
use serde::Deserialize;
use sha2::{Digest, Sha256};

/// Language-specific node kinds that drive the structural niceties (parent
/// grouping, enclosing-function for callers, go-to-def). Data, not code — so a
/// new language is fully supported by dropping a manifest, with no recompile.
#[derive(Deserialize, Clone, Default)]
pub struct Profile {
    /// Node kinds that are function/method definitions.
    #[serde(default)]
    pub function_kinds: Vec<String>,
    /// Container node kinds paired with the field that names them, e.g.
    /// `["impl_item", "type"]` or `["class_definition", "name"]`.
    #[serde(default)]
    pub containers: Vec<(String, String)>,
    /// Node kinds whose text is a usable identifier (for go-to-def).
    #[serde(default)]
    pub identifier_kinds: Vec<String>,
    /// `@reference.*` capture suffixes that denote a call site, e.g. `["call"]`
    /// for Rust/JS or `["send", "call"]` for Ruby. Empty means the default
    /// (`"call"`), which keeps every existing manifest working unchanged.
    /// Kept for manifest backward compatibility; callers now includes all reference
    /// kinds (issue #33), but the field is preserved for future precision modes.
    #[serde(default)]
    #[allow(dead_code)]
    pub call_kinds: Vec<String>,
    /// Module-path resolution strategy for import-edge go-to-def (ADR 0001
    /// Step 2): `"dotted_package"` (Python `foo.bar` → `foo/bar.py`) or
    /// `"relative_path"` (JS/TS `./bar` → `./bar.js`). `None` disables cross-file
    /// import resolution; the language keeps directory-wide name lookup.
    #[serde(default)]
    pub import_resolution: Option<String>,
}

impl Profile {
    /// Is `kind` (a `@reference.*` capture suffix) a call site? Honors the
    /// manifest's `call_kinds`, falling back to the literal `"call"` so a
    /// grammar without the field behaves exactly as before.
    ///
    /// Kept for manifest backward compatibility; callers now includes all reference
    /// kinds (issue #33), but the method is preserved for future precision modes.
    #[allow(dead_code)]
    pub fn is_call_kind(&self, kind: &str) -> bool {
        if self.call_kinds.is_empty() {
            kind == "call"
        } else {
            self.call_kinds.iter().any(|k| k == kind)
        }
    }
}

/// Where a hosted artifact was ingested from — recorded for auditability.
/// grove serves the bytes; this attributes the source.
#[derive(Deserialize, Clone)]
pub struct Source {
    pub repo: String,
    #[serde(default)]
    pub rev: String,
}

#[derive(Deserialize, Clone)]
pub struct Manifest {
    pub name: String,
    pub version: String,
    pub extensions: Vec<String>,
    #[serde(default)]
    pub source: Option<Source>,
    #[serde(default)]
    pub profile: Profile,
}

/// A resolved grammar artifact — enough to load and extract. Cheap to clone
/// (the heavy wasm bytes and query text are shared via `Arc`).
#[derive(Clone)]
pub struct Grammar {
    pub name: String,
    pub version: String,
    pub wasm: Arc<Vec<u8>>,
    pub tags_query: Arc<String>,
    /// Optional `locals.scm` (tree-sitter's standard `@local.scope` /
    /// `@local.definition` / `@local.reference` query). Drives scope-aware
    /// go-to-def. `None` when the registry dir ships no `locals.scm` — those
    /// languages keep the directory-wide name lookup.
    pub locals_query: Option<Arc<String>>,
    /// Optional `imports.scm` (grove's `@import.name` / `@import.source` /
    /// `@import.module` query). Drives import-edge cross-file go-to-def. `None`
    /// when the registry dir ships no `imports.scm`.
    pub imports_query: Option<Arc<String>>,

    pub imports_query: Option<Arc<String>>,
    pub profile: Arc<Profile>,
}

impl Grammar {
    /// sha256 of the wasm bytes — the lockfile's integrity field.
    pub fn wasm_sha256(&self) -> String {
        sha256(self.wasm.as_slice())
    }
}

/// The OS-native global cache location for grammars:
/// `~/.cache/grove/grammars` (Linux), `~/Library/Caches/grove/grammars` (macOS),
/// `%LOCALAPPDATA%\grove\grammars` (Windows). Grammars are a cache — reconstructible
/// from the hosted registry and content-addressed by `grove.lock`.
pub fn cache_root() -> Option<PathBuf> {
    dirs::cache_dir().map(|c| c.join("grove").join("grammars"))
}

/// Dev fallback: the registry shipped in the source tree (only exists in a checkout).
fn dev_root() -> PathBuf {
    PathBuf::from(concat!(env!("CARGO_MANIFEST_DIR"), "/registry"))
}

/// A candidate registry root with where it came from, for diagnostics.
pub struct RootCandidate {
    pub source: &'static str,
    pub path: PathBuf,
    pub exists: bool,
}

/// The ordered search path, first existing wins. Surfaced by `grove registry`.
pub fn search_path() -> Vec<RootCandidate> {
    let mut out = Vec::new();
    let mut add = |source, path: PathBuf| {
        let exists = path.is_dir();
        out.push(RootCandidate { source, path, exists });
    };
    if let Ok(p) = std::env::var("GROVE_REGISTRY") {
        add("GROVE_REGISTRY", PathBuf::from(p));
    }
    if let Ok(cwd) = std::env::current_dir() {
        for dir in cwd.ancestors() {
            let cand = dir.join(".grove").join("grammars");
            if cand.is_dir() {
                add("project (.grove/grammars)", cand);
                break;
            }
        }
    }
    if let Some(c) = cache_root() {
        add("user cache", c);
    }
    add("dev (source tree)", dev_root());
    out
}

/// Resolve the registry root by precedence: an explicit `GROVE_REGISTRY` always
/// wins; otherwise the first existing of project-vendored → user cache → dev tree;
/// otherwise the canonical user-cache path (so errors point at the right home).
fn registry_root() -> PathBuf {
    if let Ok(p) = std::env::var("GROVE_REGISTRY") {
        return PathBuf::from(p);
    }
    for cand in search_path() {
        if cand.exists {
            return cand.path;
        }
    }
    cache_root().unwrap_or_else(dev_root)
}

/// Index of available languages, read once from the registry manifests.
struct Index {
    root: PathBuf,
    by_name: HashMap<String, Manifest>,
    by_ext: HashMap<String, String>, // extension -> language name
}

fn index() -> &'static Index {
    static INDEX: OnceLock<Index> = OnceLock::new();
    INDEX.get_or_init(|| {
        let root = registry_root();
        let mut by_name = HashMap::new();
        let mut by_ext = HashMap::new();
        if let Ok(entries) = std::fs::read_dir(&root) {
            for e in entries.flatten() {
                let mpath = e.path().join("manifest.json");
                let Ok(text) = std::fs::read_to_string(&mpath) else {
                    continue;
                };
                let Ok(m) = serde_json::from_str::<Manifest>(&text) else {
                    continue;
                };
                for ext in &m.extensions {
                    by_ext.insert(ext.clone(), m.name.clone());
                }
                by_name.insert(m.name.clone(), m);
            }
        }
        Index { root, by_name, by_ext }
    })
}

fn cache() -> &'static Mutex<HashMap<String, Grammar>> {
    static CACHE: OnceLock<Mutex<HashMap<String, Grammar>>> = OnceLock::new();
    CACHE.get_or_init(|| Mutex::new(HashMap::new()))
}

/// Resolve a grammar by language id, reading (and caching) its artifacts.
pub fn resolve(lang: &str) -> Result<Grammar> {
    if let Some(g) = cache().lock().unwrap().get(lang) {
        return Ok(g.clone());
    }
    let idx = index();
    let manifest = idx.by_name.get(lang).with_context(|| {
        format!(
            "language `{lang}` is not in the registry ({}). Available: {}",
            idx.root.display(),
            available().join(", ")
        )
    })?;
    let dir = idx.root.join(lang);
    let wasm = std::fs::read(dir.join("grammar.wasm"))
        .with_context(|| format!("reading grammar.wasm for `{lang}`"))?;
    let tags = std::fs::read_to_string(dir.join("tags.scm"))
        .with_context(|| format!("reading tags.scm for `{lang}`"))?;
    // `locals.scm` / `imports.scm` are optional: present them only if the
    // registry dir ships them.
    let read_optional = |fname: &str| -> Result<Option<Arc<String>>> {
        match std::fs::read_to_string(dir.join(fname)) {
            Ok(s) => Ok(Some(Arc::new(s))),
            Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
            Err(e) => Err(e).with_context(|| format!("reading {fname} for `{lang}`")),
        }
    };
    let locals = read_optional("locals.scm")?;
    let imports = read_optional("imports.scm")?;
    let grammar = Grammar {
        name: manifest.name.clone(),
        version: manifest.version.clone(),
        wasm: Arc::new(wasm),
        tags_query: Arc::new(tags),
        locals_query: locals,
        imports_query: imports,
        profile: Arc::new(manifest.profile.clone()),
    };
    cache()
        .lock()
        .unwrap()
        .insert(lang.to_string(), grammar.clone());

        .insert(lang.to_string(), grammar.clone());
    Ok(grammar)
}

/// The language id for a file path, by extension.
pub fn lang_for_path(path: &Path) -> Option<&'static str> {
    let ext = path.extension()?.to_str()?;
    index().by_ext.get(ext).map(String::as_str)
}

/// Resolve the grammar for a file path.
pub fn for_path(path: &Path) -> Result<Grammar> {
    let lang = lang_for_path(path).with_context(|| {
        format!(
            "no registered grammar for `{}` (extensions: {})",
            path.display(),
            extensions().join(", ")
        )
    })?;
    resolve(lang)
}

/// True if the path has a registered extension.
pub fn is_source(path: &Path) -> bool {
    lang_for_path(path).is_some()
}

/// The registry root actually in use this run.
pub fn root() -> &'static Path {
    &index().root
}

/// All available language names.
pub fn available() -> Vec<String> {
    let mut v: Vec<String> = index().by_name.keys().cloned().collect();
    v.sort();
    v
}

/// All registered extensions.
pub fn extensions() -> Vec<String> {
    let mut v: Vec<String> = index().by_ext.keys().cloned().collect();
    v.sort();
    v
}

/// The manifests, for `grove languages`.
pub fn manifests() -> Vec<Manifest> {
    let mut v: Vec<Manifest> = index().by_name.values().cloned().collect();
    v.sort_by(|a, b| a.name.cmp(&b.name));
    v
}

/// The canonical content hash for grove artifacts: `sha256:<hex>`. The single
/// source of truth — the lockfile, the index, and `grove fetch`'s verification
/// all go through here, so the format can never drift between producer and
/// verifier.
pub fn sha256(bytes: &[u8]) -> String {
    let mut h = Sha256::new();
    h.update(bytes);
    format!("sha256:{:x}", h.finalize())
}

/// Build the hosted catalog (`index.json`) for a registry directory: per
/// language, its version, provenance, and a content hash of every served file.
/// This is what registry CI runs to publish; `grove fetch` consumes it.
///
/// When `release_base` is set, `grammar.wasm` is recorded as a release **asset**
/// (`<lang>.wasm`) served from that base, so the heavy binaries live in GitHub
/// Releases and the repo stays small. `tags.scm`/`manifest.json` are always
/// served from the repo alongside the catalog.
pub fn build_index(root: &Path, release_base: Option<&str>) -> Result<serde_json::Value> {
    let mut dirs: Vec<PathBuf> = std::fs::read_dir(root)
        .with_context(|| format!("reading registry {}", root.display()))?
        .flatten()
        .map(|e| e.path())
        .filter(|p| p.is_dir())
        .collect();
    dirs.sort();

    let mut grammars = Vec::new();
    for dir in dirs {
        let mpath = dir.join("manifest.json");
        if !mpath.exists() {
            continue;
        }
        let m: Manifest = serde_json::from_str(&std::fs::read_to_string(&mpath)?)
            .with_context(|| format!("parsing {}", mpath.display()))?;
        let mut files = serde_json::Map::new();
        for fname in ["grammar.wasm", "tags.scm", "manifest.json"] {
            let bytes = std::fs::read(dir.join(fname))
                .with_context(|| format!("hashing {}/{fname}", m.name))?;
            let mut fref = serde_json::json!({ "sha256": sha256(&bytes) });
            if fname == "grammar.wasm" && release_base.is_some() {
                fref["asset"] = serde_json::json!(format!("{}.wasm", m.name));
            }
            files.insert(fname.into(), fref);
        }
        // `locals.scm` / `imports.scm` are optional (scope-aware + import-edge
        // resolution, ADR 0001): record each only when the grammar dir ships it,
        // so `fetch` pulls it for languages that have it without breaking those
        // that don't.
        for fname in ["locals.scm", "imports.scm"] {
            let path = dir.join(fname);
            if path.exists() {
                let bytes = std::fs::read(&path)
                    .with_context(|| format!("hashing {}/{fname}", m.name))?;
                files.insert(fname.into(), serde_json::json!({ "sha256": sha256(&bytes) }));
            }
        }
        let mut entry = serde_json::json!({
            "name": m.name,
            "version": m.version,
            "extensions": m.extensions,
            "files": files,
        });
        if let Some(src) = &m.source {
            entry["source"] = serde_json::json!({ "repo": src.repo, "rev": src.rev });
        }
        grammars.push(entry);
    }
    let mut catalog = serde_json::json!({ "schema": 2, "grammars": grammars });
    if let Some(base) = release_base {
        catalog["release_base"] = serde_json::json!(base);
    }
    Ok(catalog)
}

/// Build the registry catalog and write it as JSON. `dir` defaults to the
/// resolved registry root; `output` defaults to `<dir>/index.json`. Returns the
/// path written and the grammar count, for the caller to report. Keeps path
/// resolution and file I/O out of `main`, alongside its sibling verbs.
pub fn write_index(
    dir: Option<PathBuf>,
    output: Option<PathBuf>,
    release_base: Option<&str>,
) -> Result<(PathBuf, usize)> {
    let dir = dir.unwrap_or_else(|| root().to_path_buf());
    let out = output.unwrap_or_else(|| dir.join("index.json"));
    let catalog = build_index(&dir, release_base)?;
    std::fs::write(&out, format!("{}\n", serde_json::to_string_pretty(&catalog)?))
        .with_context(|| format!("writing {}", out.display()))?;
    let n = catalog["grammars"].as_array().map_or(0, |a| a.len());
    Ok((out, n))
}

/// Write a lockfile pinning every registry grammar's version + wasm hash.
pub fn write_lock(path: &Path) -> Result<usize> {
    write_lock_for(&available(), path)
}

/// Write a lockfile pinning the given languages' version + wasm hash.
/// Deterministic (sorted) so it is diff-friendly and commit-able.
pub fn write_lock_for(langs: &[String], path: &Path) -> Result<usize> {
    let mut names: Vec<String> = langs.to_vec();
    names.sort();
    names.dedup();
    let mut grammars = Vec::new();
    for name in &names {
        let g = resolve(name)?;
        grammars.push(serde_json::json!({
            "name": g.name,
            "version": g.version,
            "wasm": g.wasm_sha256(),
        }));
    }
    let doc = serde_json::json!({ "version": 1, "grammars": grammars });
    std::fs::write(path, format!("{}\n", serde_json::to_string_pretty(&doc)?))
        .with_context(|| format!("writing {}", path.display()))?;
    Ok(grammars.len())
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn empty_call_kinds_defaults_to_literal_call() {
        // A manifest with no `call_kinds` (every grammar shipped before #10)
        // must keep treating `@reference.call` as the call site.
        let p = Profile::default();
        assert!(p.is_call_kind("call"));
        assert!(!p.is_call_kind("send"));
        assert!(!p.is_call_kind("invocation"));
    }

    #[test]
    fn call_kinds_drives_the_filter() {
        // A Ruby/Elixir-style grammar declares its own call suffixes; the
        // literal "call" is no longer special once the field is set.
        let p = Profile { call_kinds: vec!["send".into(), "invocation".into()], ..Default::default() };
        assert!(p.is_call_kind("send"));
        assert!(p.is_call_kind("invocation"));
        assert!(!p.is_call_kind("call"));
    }

    /// A minimal one-grammar registry dir that `build_index` can hash.
    fn toy_registry(tag: &str) -> PathBuf {
        let dir = std::env::temp_dir().join(format!("grove_index_test_{}_{tag}", std::process::id()));
        let lang = dir.join("toy");
        std::fs::create_dir_all(&lang).unwrap();
        std::fs::write(lang.join("grammar.wasm"), b"\0asm-toy-bytes").unwrap();
        std::fs::write(lang.join("tags.scm"), "; tags").unwrap();
        std::fs::write(lang.join("manifest.json"), r#"{"name":"toy","version":"1.2.3","extensions":["toy"]}"#).unwrap();
        dir
    }

    #[test]
    fn write_index_writes_catalog_and_returns_count() {
        let dir = toy_registry("explicit");
        let out = dir.join("custom.json");

        let (written, n) = write_index(Some(dir.clone()), Some(out.clone()), None).unwrap();
        assert_eq!(written, out, "returns the path it wrote");
        assert_eq!(n, 1, "one grammar in the toy registry");

        let catalog: serde_json::Value =
            serde_json::from_str(&std::fs::read_to_string(&out).unwrap()).unwrap();
        assert_eq!(catalog["schema"], serde_json::json!(2));
        assert_eq!(catalog["grammars"][0]["name"], serde_json::json!("toy"));
        assert!(catalog["grammars"][0]["files"]["grammar.wasm"]["sha256"]
            .as_str().unwrap().starts_with("sha256:"));

        std::fs::remove_dir_all(&dir).ok();
    }

    #[test]
    fn build_index_records_locals_scm_only_when_present() {
        // Absent by default: the toy registry ships no locals.scm.
        let dir = toy_registry("no_locals");
        let catalog = build_index(&dir, None).unwrap();
        assert!(
            catalog["grammars"][0]["files"].get("locals.scm").is_none(),
            "no locals.scm in the dir → none in the catalog"
        );
        std::fs::remove_dir_all(&dir).ok();

        // Present: dropping a locals.scm in the dir surfaces it (hashed) in the
        // catalog, so `fetch` will pull it (it's repo-served, no asset).
        let dir = toy_registry("with_locals");
        std::fs::write(dir.join("toy").join("locals.scm"), "(identifier) @local.reference\n").unwrap();
        let catalog = build_index(&dir, None).unwrap();
        let entry = &catalog["grammars"][0]["files"]["locals.scm"];
        assert!(
            entry["sha256"].as_str().unwrap().starts_with("sha256:"),
            "locals.scm hashed into the catalog: {entry}"
        );
        assert!(entry.get("asset").is_none(), "locals.scm is repo-served, not a release asset");
        std::fs::remove_dir_all(&dir).ok();
    }

//! `grove fetch` — pull grammars from the hosted registry into the OS cache.
//!
//! Host model: a `grove-registry` GitHub repo served via jsDelivr's GitHub CDN,
//! laid out as `<host>/index.json` (the catalog) and `<host>/<lang>/{grammar.wasm,
//! tags.scm, manifest.json}`. Each wasm's sha256 is verified against the catalog
//! before it lands in the cache. Override the host with `GROVE_REGISTRY_URL`.

use std::io::Read;

use anyhow::{anyhow, bail, Context, Result};
use serde::Deserialize;

use crate::registry;
use crate::registry::sha256;

/// Default host for the catalog + per-language text files (tags.scm, manifest).
/// raw.githubusercontent serves these reliably (jsDelivr's per-file cold-fetch
/// 502s intermittently). The heavy wasm binaries are GitHub Release assets (see
/// `release_base` in the catalog), so this stays light. Override with
/// `GROVE_REGISTRY_URL` to self-host or mirror.
const DEFAULT_HOST: &str = "https://raw.githubusercontent.com/Entelligentsia/grove-registry/v1";

#[derive(Deserialize)]
struct Catalog {
    /// Base URL for release-asset files (GitHub Releases); needed if any file
    /// entry has an `asset`.
    #[serde(default)]
    release_base: Option<String>,
    #[serde(default)]
    grammars: Vec<CatEntry>,
}

#[derive(Deserialize)]
struct CatEntry {
    name: String,
    version: String,
    /// File extensions this grammar handles (schema 2+); used by `grove init`
    /// to detect a project's languages before any grammar is fetched.
    #[serde(default)]
    extensions: Vec<String>,
    /// filename → where/what to fetch + its hash.
    #[serde(default)]
    files: std::collections::HashMap<String, FileRef>,
}

/// A grammar as listed in the hosted catalog: its id and the extensions it
/// covers. `grove init` maps a project's files to languages through this — the
/// full set, not just what's already cached.
pub struct CatalogGrammar {
    pub name: String,
    pub extensions: Vec<String>,
}

/// Fetch the hosted catalog and return every grammar's id + extensions.
pub fn catalog_grammars() -> Result<Vec<CatalogGrammar>> {
    let host = host();
    let catalog: Catalog = serde_json::from_slice(&get_bytes(&format!("{host}/index.json"))?)
        .context("parsing index.json catalog")?;
    Ok(catalog
        .grammars
        .into_iter()
        .map(|g| CatalogGrammar { name: g.name, extensions: g.extensions })
        .collect())
}

#[derive(Deserialize)]
struct FileRef {
    sha256: String,
    /// If set, the file is a release asset of this name under `release_base`;
    /// otherwise it sits in the repo at `<host>/<lang>/<filename>`.
    #[serde(default)]
    asset: Option<String>,
}

fn host() -> String {
    std::env::var("GROVE_REGISTRY_URL")
        .unwrap_or_else(|_| DEFAULT_HOST.to_string())
        .trim_end_matches('/')
        .to_string()
}

//! `grove init` — make a project one where the agent actually uses grove.
//!
//! Two halves, per VISION §6.4.1: registration (`.mcp.json`) makes the tools
//! *available*; a steering directive (`CLAUDE.md`) makes them *adopted*. Plus a
//! `grove.lock` pinning the grammars the project needs. Idempotent: re-running
//! updates the grove pieces without clobbering anything else.

use std::collections::{BTreeMap, HashMap};
use std::path::Path;

use anyhow::{Context, Result};
use clap::ValueEnum;
use ignore::WalkBuilder;
use serde_json::{json, Value};

use crate::{fetch, registry};

const CLAUDE_START: &str = "<!-- grove:start -->";
const CLAUDE_END: &str = "<!-- grove:end -->";

/// Which integration `grove init` wires up. Grammar provisioning (fetch +
/// `grove.lock`) happens for every target; this only selects the harness glue.
#[derive(Clone, Copy, Debug, Default, PartialEq, Eq, ValueEnum)]
pub enum Target {
    /// Register the MCP server (`.mcp.json`) + a CLAUDE.md steering block.
    #[default]
    Mcp,
    /// Grammars + a CLAUDE.md steering block (so a cold agent actually reaches
    /// for grove instead of grep). The skill *artifact* is distributed via the
    /// skills tool (`npx skills add Entelligentsia/grove`); init provisions and
    /// steers — steering to the grove skill / CLI rather than MCP tools.
    Skill,
    /// Both of the above.
    Both,
    /// Grammars + `grove.lock` only — no `.mcp.json`, no CLAUDE.md steering.
    /// For embedding hosts (e.g. an editor or agent runtime) that register
    /// grove's tools themselves and supply their own steering; the project's
    /// own files are left untouched.
    Grammars,
}

impl Target {
    fn writes_mcp(self) -> bool {
        matches!(self, Target::Mcp | Target::Both)
    }
    fn is_skill(self) -> bool {
        matches!(self, Target::Skill | Target::Both)
    }
    /// Whether this target writes a CLAUDE.md steering block. Every target but
    /// `Grammars` does — `Grammars` provisions grammars + the lock and nothing
    /// else, leaving project-owned files (CLAUDE.md, `.mcp.json`) untouched.
    fn writes_steering(self) -> bool {
        !matches!(self, Target::Grammars)
    }
}

/// The key grove registers itself under in `.mcp.json`. Claude Code namespaces
/// an MCP server's tools as `mcp__<key>__<tool>`, so this also determines the
/// tool prefix the steering directive must use to name the real tools.
const MCP_SERVER_KEY: &str = "grove";

pub fn run(root: &Path, target: Target, dry_run: bool) -> Result<()> {
    println!("grove init  scanning {} (as {:?})\n", root.display(), target);

    // 1. Build an extension→language map. Prefer the hosted catalog so we detect
    //    languages whose grammar isn't fetched yet (otherwise a project's main
    //    language is silently skipped); fall back to cached grammars offline.
    let (ext_map, online) = extension_map();

    // 2. Count project files per language.
    let mut counts: BTreeMap<String, usize> = BTreeMap::new();
    for entry in WalkBuilder::new(root).build().flatten() {
        let p = entry.path();
        if p.is_file() {
            if let Some(ext) = p.extension().and_then(|e| e.to_str()) {
                if let Some(lang) = ext_map.get(ext) {
                    *counts.entry(lang.clone()).or_default() += 1;
                }
            }
        }
    }

    if counts.is_empty() {
        println!("  no files matched a known grammar.");
        println!("  nothing to do.");
        return Ok(());
    }
    for (lang, n) in &counts {
        println!("  detected   {:<10} {} files", lang, n);
    }
    let langs: Vec<String> = counts.keys().cloned().collect();

    if dry_run {
        println!("\n  (dry run — no files written)");
        return Ok(());
    }

    // 3. Auto-fetch any detected grammar the cache doesn't have yet, so the
    //    tools work the moment init finishes. (Checked against the filesystem,
    //    not the in-memory registry index, which we must not build before the

    //    not the in-memory registry index, which we must not build before the
    //    fetch lands — it is cached on first access.)
    let missing: Vec<String> = langs.iter().filter(|l| !is_cached(l)).cloned().collect();
    if !missing.is_empty() {
        if online {
            println!("\n  fetching   {} grammar(s): {}\n", missing.len(), missing.join(", "));
            fetch::run(&missing, false).context("auto-fetching detected grammars")?;
        } else {
            println!(
                "\n  note       {} not cached: {}\n             offline — run `grove fetch {}` to enable them.",
                if missing.len() == 1 { "language" } else { "languages" },
                missing.join(", "),
                missing.join(" "),
            );
        }
    }

    // 4. Provision grammars (every target) + write the harness glue. The lock
    //    and a CLAUDE.md steering block are written for every target; `.mcp.json`
    //    only for MCP targets. Steering is not optional: without it a cold agent
    //    ignores grove and falls back to grep/whole-file reads (VISION §6.4.1).
    //    The skill artifact itself still comes from the skills tool, not init.
    let langs: Vec<String> = langs.into_iter().filter(|l| is_cached(l)).collect();
    if langs.is_empty() {
        println!("\n  no grammars available — nothing written.");
        return Ok(());
    }
    let wrote = write_harness(root, target, &langs)?;

    println!("\n  wrote");
    for w in &wrote {
        println!("             ✓ {w}");
    }
    if target.writes_mcp() {
        println!("\n  ready      your agent now has grove's tools across its loop:");
        println!("             outline · symbols · source · callers · map · definition · check");
        println!("\n  try it     start a fresh Claude Code session here and ask a");
        println!("             \"where/what/who-calls\" question — it routes through grove.");
    }
    if target.is_skill() {
        println!("\n  skill      grammars + steering are ready. Install the cross-harness");
        println!("             skill with:  npx skills add Entelligentsia/grove");
        println!("             (it steers your agent to grove's MCP tools when present,");
        println!("              else the grove CLI — same engine either way.)");
    }
    if !target.writes_steering() {
        println!("\n  grammars   provisioned + pinned (grove.lock). No project files were");
        println!("             modified — the embedding host registers grove's tools and");
        println!("             supplies its own steering.");
    }
    Ok(())
}

/// Write the harness glue for `target` and pin `grove.lock`. The lock and a
/// CLAUDE.md steering block are written for every target; `.mcp.json` only for
/// MCP targets. Returns a human list of what was written, in order.
fn write_harness(root: &Path, target: Target, langs: &[String]) -> Result<Vec<String>> {
    let mut wrote = Vec::new();
    if target.writes_mcp() {
        wrote.push(write_mcp_json(root)?);
    }
    // Steering for every target except `Grammars` — availability isn't adoption
    // (VISION §6.4.1), but embedding hosts supply their own steering and want
    // project files left untouched.
    if target.writes_steering() {
        wrote.push(write_claude_md(root, langs, target)?);
    }
    let n = registry::write_lock_for(langs, &root.join("grove.lock"))?;
    wrote.push(format!("grove.lock ({n} grammars)"));
    Ok(wrote)
}

/// Extension→language map and whether it came from the hosted catalog (`true`,
/// covering all languages) or — when offline — the local cache (`false`).
fn extension_map() -> (HashMap<String, String>, bool) {
    match fetch::catalog_grammars() {
        Ok(grammars) => {
            let mut m = HashMap::new();
            for g in &grammars {
                for ext in &g.extensions {
                    m.insert(ext.clone(), g.name.clone());
                }
            }
            (m, true)
        }
        Err(e) => {
            eprintln!("  note: catalog unavailable ({e}); detecting from cached grammars only.");
            let mut m = HashMap::new();
            for man in registry::manifests() {
                for ext in &man.extensions {
                    m.insert(ext.clone(), man.name.clone());
                }
            }
            (m, false)
        }
    }
}

/// True if `lang`'s grammar is already in the OS cache. Checks the filesystem
/// directly so it never triggers the (once-initialised) in-memory registry index.
fn is_cached(lang: &str) -> bool {
    registry::cache_root().is_some_and(|c| c.join(lang).join("grammar.wasm").exists())
}

/// Add (or refresh) the grove MCP server in `.mcp.json`, preserving other servers.
fn write_mcp_json(root: &Path) -> Result<String> {
    let path = root.join(".mcp.json");
    let mut doc: Value = match std::fs::read_to_string(&path) {
        Ok(text) => serde_json::from_str(&text)
            .with_context(|| format!("{} is not valid JSON", path.display()))?,
        Err(_) => json!({}),
    };
    if !doc.is_object() {
        doc = json!({});
    }
    let exe = std::env::current_exe().context("locating the grove binary")?;
    doc["mcpServers"][MCP_SERVER_KEY] = json!({
        "command": exe.to_string_lossy(),
        "args": ["serve"],
    });
    std::fs::write(&path, format!("{}\n", serde_json::to_string_pretty(&doc)?))
        .with_context(|| format!("writing {}", path.display()))?;
    Ok(".mcp.json (registration — the tools exist)".to_string())
}

/// Write/refresh the grove steering section in `CLAUDE.md`, between markers, so
/// re-running is idempotent and never disturbs the rest of the file.
fn write_claude_md(root: &Path, langs: &[String], target: Target) -> Result<String> {
    let path = root.join("CLAUDE.md");
    let section = claude_section(langs, target);
    let existing = std::fs::read_to_string(&path).ok();
    let updated = match existing {
        Some(text) if text.contains(CLAUDE_START) && text.contains(CLAUDE_END) => {
            let start = text.find(CLAUDE_START).unwrap();
            let end = text.find(CLAUDE_END).unwrap() + CLAUDE_END.len();
            format!("{}{}{}", &text[..start], section, &text[end..])
        }
        Some(text) => format!("{}\n\n{}\n", text.trim_end(), section),
        None => format!("{section}\n"),
    };
    std::fs::write(&path, updated).with_context(|| format!("writing {}", path.display()))?;
    Ok("CLAUDE.md (steering — the tools get used)".to_string())
}

/// The steering block, tailored to how the agent reaches grove. The MCP target
/// carries the full route-by-task guide inline (there is no skill file to defer
/// to); the skill target is a thin version that defers to SKILL.md as the single
/// source of truth. Both route by task — grove for named symbols / structure, the
/// shell for text / non-code / quick facts, combining freely — rather than banning
/// grep: a cold agent with no block at all defaults to grep / whole-file reads
/// (VISION §6.4.1), and an over-rigid "grove or violation" block overcorrects into

//! `grove ingest` — build registry artifacts from curated source specs.
//!
//! For each grammar in the sources file, pull its **official tree-sitter release
//! wasm** (native `dylink.0`) + the repo's `tags.scm`, attach grove's curated
//! profile/extensions, and lay out `<out>/<lang>/{grammar.wasm, tags.scm,
//! manifest.json}`, then regenerate `index.json`. This is the registry's build
//! step (CI / maintainer), not an end-user command.

use std::path::Path;

use anyhow::{bail, Context, Result};
use serde::Deserialize;
use serde_json::Value;

use crate::{fetch, registry};

#[derive(Deserialize)]
struct Sources {
    #[serde(default)]
    grammars: Vec<Spec>,
}

#[derive(Deserialize)]
struct Spec {
    name: String,
    /// GitHub repo, e.g. `tree-sitter/tree-sitter-python`.
    repo: String,
    /// Release tag, e.g. `v0.25.0`.
    rev: String,
    /// Release asset filename, e.g. `tree-sitter-python.wasm`.
    wasm_asset: String,
    /// Path to the tags query in the repo at `rev`.
    #[serde(default = "default_tags")]
    tags_path: String,
    /// Path to the locals query in the repo at `rev` (scope-aware resolution,
    /// ADR 0001). Optional — many grammars ship one here; if it's absent upstream
    /// the language simply keeps directory-wide name lookup.
    #[serde(default = "default_locals")]
    locals_path: String,
    /// Curated query patterns appended after the upstream `tags.scm`. Lets grove
    /// fill gaps in an upstream query (e.g. C ships no rule for file-scope
    /// variable/array definitions) without forking the whole file. Patterns are
    /// appended verbatim, so they must use the same `@definition.*`/`@name`
    /// captures the engine interprets.
    #[serde(default)]
    extra_tags: String,
    extensions: Vec<String>,
    profile: Value,
}

fn default_tags() -> String {
    "queries/tags.scm".to_string()
}

fn default_locals() -> String {
    "queries/locals.scm".to_string()
}

/// Ingest one grammar; returns (wasm KB, has_tags). Errors are per-language.
fn ingest_one(s: &Spec, out: &Path) -> Result<(usize, bool)> {
    let version = s.rev.trim_start_matches('v').to_string();

    let wasm_url = format!(
        "https://github.com/{}/releases/download/{}/{}",
        s.repo, s.rev, s.wasm_asset
    );
    let wasm = fetch::get_bytes(&wasm_url).with_context(|| format!("wasm {wasm_url}"))?;
    if !wasm.windows(8).any(|w| w == b"dylink.0") {
        bail!("{} is not a native (dylink.0) module", s.wasm_asset);
    }

    // tags.scm is optional: not every grammar ships one (css/html/json have no
    // definitions to extract). Without it the grammar still parses and `check`s;
    // the symbol tools are graceful no-ops.
    let tags_url = format!(
        "https://raw.githubusercontent.com/{}/{}/{}",
        s.repo, s.rev, s.tags_path
    );
    let (mut tags, has_tags) = match fetch::get_bytes(&tags_url) {
        Ok(t) => (t, true),
        Err(_) => (b"; no upstream tags query for this grammar\n".to_vec(), false),
    };
    if !s.extra_tags.is_empty() {
        if !tags.ends_with(b"\n") {
            tags.push(b'\n');
        }
        tags.extend_from_slice(b"\n; --- grove curated additions ---\n");
        tags.extend_from_slice(s.extra_tags.as_bytes());
        if !s.extra_tags.ends_with('\n') {
            tags.push(b'\n');
        }
    }

    // locals.scm is optional too: fetch it if upstream ships one at `locals_path`,
    // otherwise the language keeps directory-wide name lookup (no scope-aware
    // go-to-def). A 404 is not an error.
    let locals_url = format!(
        "https://raw.githubusercontent.com/{}/{}/{}",
        s.repo, s.rev, s.locals_path
    );

